// Generated by Claude Opus 4.6

import { act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import React from 'react';

import DevfileEditorTools from '@/components/DevfileEditorTools';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

// mute console.error
console.error = jest.fn();

const mockClipboard = jest.fn();
jest.mock('react-copy-to-clipboard', () => {
  return {
    __esModule: true,
    default: (props: { text: string; onCopy: () => void; children: React.ReactNode }) => {
      return (
        <button
          onClick={() => {
            mockClipboard(props.text);
            props.onCopy();
          }}
        >
          {props.children}
        </button>
      );
    },
  };
});

const mockOnToggleExpand = jest.fn();

const { renderComponent } = getComponentRenderer(getComponent);

describe('DevfileEditorTools', () => {
  beforeEach(() => {
    jest.useFakeTimers();
    URL.createObjectURL = jest.fn().mockReturnValue('blob:test-url');
  });

  afterEach(() => {
    jest.clearAllMocks();
    jest.clearAllTimers();
  });

  describe('Expand/Compress', () => {
    test('should render Expand button when not expanded', () => {
      renderComponent('content', 'my-workspace', false);

      expect(screen.getByText('Expand')).toBeTruthy();
      expect(screen.queryByText('Compress')).toBeNull();
    });

    test('should render Compress button when expanded', () => {
      renderComponent('content', 'my-workspace', true);

      expect(screen.getByText('Compress')).toBeTruthy();
      expect(screen.queryByText('Expand')).toBeNull();
    });

    test('should call onToggleExpand when Expand button is clicked', async () => {
      const user = userEvent.setup({ advanceTimers: jest.advanceTimersByTime });
      renderComponent('content', 'my-workspace', false);

      const expandButton = screen.getByRole('button', { name: /Expand/ });
      await user.click(expandButton);

      expect(mockOnToggleExpand).toHaveBeenCalledTimes(1);
    });

    test('should call onToggleExpand when Compress button is clicked', async () => {
      const user = userEvent.setup({ advanceTimers: jest.advanceTimersByTime });
      renderComponent('content', 'my-workspace', true);

      const compressButton = screen.getByRole('button', { name: /Compress/ });
      await user.click(compressButton);

      expect(mockOnToggleExpand).toHaveBeenCalledTimes(1);
    });
  });

  describe('Copy to clipboard', () => {
    test('should show Copy to clipboard button when not readOnly', () => {
      renderComponent('content', 'my-workspace', false);

      expect(screen.getByText('Copy to clipboard')).toBeTruthy();
    });

    test('should not show Copy to clipboard button when readOnly', () => {
      renderComponent('content', 'my-workspace', false, true);

      expect(screen.queryByText('Copy to clipboard')).toBeNull();
    });

    test('should copy content and show Copied text', async () => {
      const user = userEvent.setup({ advanceTimers: jest.advanceTimersByTime });
      const contentText = 'schemaVersion: 2.1.0\nmetadata:\n  name: test\n';
      renderComponent(contentText, 'my-workspace', false);

      const copyButton = screen.getByText('Copy to clipboard');
      await user.click(copyButton);

      expect(mockClipboard).toHaveBeenCalledWith(contentText);
      expect(screen.getByText('Copied')).toBeTruthy();
      expect(screen.queryByText('Copy to clipboard')).toBeNull();
    });

    test('should revert back to Copy to clipboard after timeout', async () => {
      const user = userEvent.setup({ advanceTimers: jest.advanceTimersByTime });
      renderComponent('content', 'my-workspace', false);

      const copyButton = screen.getByText('Copy to clipboard');
      await user.click(copyButton);

      expect(screen.getByText('Copied')).toBeTruthy();

      act(() => {
        jest.advanceTimersByTime(4000);
      });

      expect(screen.getByText('Copy to clipboard')).toBeTruthy();
      expect(screen.queryByText('Copied')).toBeNull();
    });

    test('should reset timer on multiple clicks', async () => {
      const user = userEvent.setup({ advanceTimers: jest.advanceTimersByTime });
      renderComponent('content', 'my-workspace', false);

      const copyButton = screen.getByText('Copy to clipboard');
      await user.click(copyButton);

      act(() => {
        jest.advanceTimersByTime(2000);
      });

      // click again before timeout
      const copiedButton = screen.getByText('Copied');
      await user.click(copiedButton);

      expect(mockClipboard).toHaveBeenCalledTimes(2);

      // advance past original timeout - should still show Copied
      act(() => {
        jest.advanceTimersByTime(2000);
      });
      expect(screen.getByText('Copied')).toBeTruthy();

      // advance past new timeout
      act(() => {
        jest.advanceTimersByTime(2000);
      });
      expect(screen.getByText('Copy to clipboard')).toBeTruthy();
    });
  });

  describe('Download', () => {
    test('should show Download button when not readOnly', () => {
      renderComponent('content', 'my-workspace', false);

      expect(screen.getByText('Download')).toBeTruthy();
    });

    test('should not show Download button when readOnly', () => {
      renderComponent('content', 'my-workspace', false, true);

      expect(screen.queryByText('Download')).toBeNull();
    });

    test('should set correct download filename', () => {
      renderComponent('content', 'my-workspace', false);

      const downloadLink = screen.getByText('Download').closest('a');
      expect(downloadLink).toBeTruthy();
      expect(downloadLink?.getAttribute('download')).toBe('my-workspace.devfile.yaml');
    });

    test('should create blob URL for download', () => {
      renderComponent('devfile-content', 'my-workspace', false);

      expect(URL.createObjectURL).toHaveBeenCalled();
    });
  });

  describe('Title and status label', () => {
    test('should render title when provided', () => {
      renderComponent('content', 'my-workspace', false, false, 'My Title');

      expect(screen.getByText('My Title')).toBeTruthy();
    });

    test('should not render title when not provided', () => {
      renderComponent('content', 'my-workspace', false);

      expect(screen.queryByText('My Title')).toBeNull();
    });

    test('should render status label when provided', () => {
      renderComponent('content', 'my-workspace', false, false, undefined, <span>Status OK</span>);

      expect(screen.getByText('Status OK')).toBeTruthy();
    });
  });

  describe('ReadOnly mode', () => {
    test('should hide copy/download buttons but keep expand button', () => {
      renderComponent('content', 'my-workspace', false, true);

      expect(screen.queryByText('Copy to clipboard')).toBeNull();
      expect(screen.queryByText('Download')).toBeNull();
      expect(screen.getByText('Expand')).toBeTruthy();
    });
  });

  describe('Content updates', () => {
    test('should update blob URL when content changes', () => {
      const { reRenderComponent } = renderComponent('initial content', 'my-workspace', false);

      const initialCallCount = (URL.createObjectURL as jest.Mock).mock.calls.length;

      reRenderComponent('updated content', 'my-workspace', false);

      expect((URL.createObjectURL as jest.Mock).mock.calls.length).toBeGreaterThan(
        initialCallCount,
      );
    });

    test('should not update blob URL when content stays the same', () => {
      const { reRenderComponent } = renderComponent('same content', 'my-workspace', false);

      const initialCallCount = (URL.createObjectURL as jest.Mock).mock.calls.length;

      reRenderComponent('same content', 'my-workspace', false);

      expect((URL.createObjectURL as jest.Mock).mock.calls.length).toBe(initialCallCount);
    });
  });
});

function getComponent(
  contentText: string,
  workspaceName: string,
  isExpanded: boolean,
  readOnly?: boolean,
  title?: string,
  statusLabel?: React.ReactNode,
): React.ReactElement {
  return (
    <DevfileEditorTools
      contentText={contentText}
      workspaceName={workspaceName}
      isExpanded={isExpanded}
      readOnly={readOnly}
      onToggleExpand={mockOnToggleExpand}
      title={title}
      statusLabel={statusLabel}
    />
  );
}
